import fs from "node:fs/promises";
import path from "node:path";
import os from "node:os";

export interface Goal {
  id: string;
  description: string;
  status: "pending" | "in_progress" | "completed" | "abandoned";
  createdAt: number;
  updatedAt: number;
  completedAt?: number;
  dependencies: string[];
  priority: number;
  tags: string[];
}

export interface Project {
  id: string;
  name: string;
  description: string;
  goals: Goal[];
  status: "active" | "paused" | "completed" | "archived";
  createdAt: number;
  updatedAt: number;
}

export interface Plan {
  projects: Project[];
  lastUpdated: number;
}

export class StrategicPlanner {
  private planPath: string;
  private plan: Plan;

  constructor(planFilePath?: string) {
    if (planFilePath) {
      this.planPath = planFilePath;
    } else {
      const dir = path.join(os.homedir(), ".echo", "plans");
      this.planPath = path.join(dir, "strategic_plan.json");
    }
    this.plan = { projects: [], lastUpdated: Date.now() };
  }

  async initialize(): Promise<void> {
    try {
      await this.load();
    } catch {
      this.plan = { projects: [], lastUpdated: Date.now() };
      await this.save();
    }
  }

  async load(): Promise<Plan> {
    const data = await fs.readFile(this.planPath, "utf-8");
    this.plan = JSON.parse(data);
    return this.plan;
  }

  async save(): Promise<void> {
    this.plan.lastUpdated = Date.now();
    await fs.mkdir(path.dirname(this.planPath), { recursive: true });
    await fs.writeFile(this.planPath, JSON.stringify(this.plan, null, 2));
  }

  getPlan(): Plan {
    return this.plan;
  }

  generateId(): string {
    return `_${Date.now().toString(36)}_${Math.random().toString(36).substr(2, 9)}`;
  }

  createProject(name: string, description: string): Project {
    const now = Date.now();
    return {
      id: this.generateId(),
      name,
      description,
      goals: [],
      status: "active",
      createdAt: now,
      updatedAt: now,
    };
  }

  createGoal(description: string, options?: Partial<Goal>): Goal {
    const now = Date.now();
    return {
      id: this.generateId(),
      description,
      status: "pending",
      createdAt: now,
      updatedAt: now,
      dependencies: options?.dependencies || [],
      priority: options?.priority ?? 5,
      tags: options?.tags || [],
    };
  }

  async addProject(project: Project): Promise<void> {
    await this.initialize();
    this.plan.projects.push(project);
    await this.save();
  }

  async addGoalToProject(projectId: string, goal: Goal): Promise<boolean> {
    await this.initialize();
    const project = this.plan.projects.find(p => p.id === projectId);
    if (!project) return false;
    project.goals.push(goal);
    project.updatedAt = Date.now();
    await this.save();
    return true;
  }

  async updateGoalStatus(projectId: string, goalId: string, status: Goal["status"]): Promise<boolean> {
    await this.initialize();
    const project = this.plan.projects.find(p => p.id === projectId);
    if (!project) return false;
    const goal = project.goals.find(g => g.id === goalId);
    if (!goal) return false;
    goal.status = status;
    goal.updatedAt = Date.now();
    if (status === "completed") {
      goal.completedAt = Date.now();
    }
    project.updatedAt = Date.now();
    await this.save();
    return true;
  }

  getActiveGoals(): { project: Project; goal: Goal }[] {
    const active: { project: Project; goal: Goal }[] = [];
    for (const project of this.plan.projects) {
      if (project.status !== "active") continue;
      for (const goal of project.goals) {
        if (goal.status === "in_progress" || goal.status === "pending") {
          active.push({ project, goal });
        }
      }
    }
    return active.sort((a, b) => b.goal.priority - a.goal.priority);
  }

  getProjectSummary(projectId: string): string | null {
    const project = this.plan.projects.find(p => p.id === projectId);
    if (!project) return null;
    const completed = project.goals.filter(g => g.status === "completed").length;
    const total = project.goals.length;
    return `${project.name}: ${completed}/${total} goals completed (${total > 0 ? Math.round((completed / total) * 100) : 0}%)`;
  }

  getAllSummaries(): string[] {
    return this.plan.projects
      .filter(p => p.status === "active")
      .map(p => this.getProjectSummary(p.id)!)
      .filter(Boolean);
  }
}

import fs from "node:fs/promises";
import path from "node:path";
import { config } from "../utils/config";

export interface Message {
  role: "system" | "user" | "assistant" | "tool";
  content?: string | null;
  reasoning_content?: string | null;
  tool_calls?: any[];
  tool_call_id?: string;
  name?: string;
}

export class MemoryManager {
  private messages: Message[] = [];
  private sessionFile: string;
  private currentTokens: number = 0;
  private dirtyCount: number = 0;
  private readonly SAVE_INTERVAL = 1;

  constructor() {
    const timestamp = Date.now();
    this.sessionFile = path.join(config.HISTORY_DIR, `session_${timestamp}.json`);
  }

  getMessages(): Message[] {
    return this.messages;
  }

  async addMessage(msg: Message) {
    this.messages.push(msg);
    this.currentTokens += this.estimateTokens(JSON.stringify(msg));
    this.dirtyCount++;

    if (this.currentTokens > config.MAX_CONTEXT_TOKENS) {
      await this.save(); // Pruning required
      this.dirtyCount = 0;
    } else if (this.dirtyCount >= this.SAVE_INTERVAL) {
      await this.save();
      this.dirtyCount = 0;
    }
  }

  /**
   * Surgical Memory Rewind: Removes the last assistant message and everything after it.
   */
  async rewind() {
    for (let i = this.messages.length - 1; i >= 0; i--) {
      const msg = this.messages[i];
      if (msg && msg.role === "assistant") {
        console.log(`[MEMORY] Rewinding: Removing corrupted assistant message at index ${i}`);
        this.messages.splice(i);
        break;
      }
    }
    // Re-calculate token count after rewind
    this.currentTokens = this.messages.reduce((sum, m) => sum + this.estimateTokens(JSON.stringify(m)), 0);
    await this.save();
  }

  private estimateTokens(text: string): number {
    return Math.ceil(text.length / 4);
  }

  async save() {
    if (this.messages.length === 0) return;

    const systemMessage = this.messages[0]!;
    let currentTokens = this.estimateTokens(JSON.stringify(systemMessage));
    const historyToKeep: Message[] = [];

    // Accumulate from end until limit
    for (let i = this.messages.length - 1; i > 0; i--) {
      const msg = this.messages[i];
      if (!msg) continue;
      const msgTokens = this.estimateTokens(JSON.stringify(msg));
      if (currentTokens + msgTokens > config.MAX_CONTEXT_TOKENS) break;
      historyToKeep.unshift(msg);
      currentTokens += msgTokens;
    }

    // C1: Repair pruning boundary to prevent orphaned tool messages
    while (historyToKeep.length > 0 && historyToKeep[0]!.role === "tool") {
      console.log("[MEMORY] Pruning boundary repair: dropping orphaned tool message");
      historyToKeep.shift();
    }

    const pruned = [systemMessage, ...historyToKeep];
    this.messages = pruned; // Update in-memory state
    this.currentTokens = currentTokens; // Update tracked token count
    await fs.writeFile(this.sessionFile, JSON.stringify(pruned, null, 2));
  }

  getSessionFile(): string {
    return this.sessionFile;
  }
}

